INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
VALUES ('0ce20ab3-3ae8-4ccf-964d-4c1701aff64d', 'gn', 4, 1, NULL, 'Patrística', 'Caim e Abel. Clemente de Roma vê nesta narrativa o primeiro crime e a consequência do pecado.', 'Clemente de Roma', 'commentary', '#6B21A8', NOW());

INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at)
