VALUES ('16847554-36e2-43ac-a872-c3d6f1a068fd', '1rs', 2, 1, NULL, 'Patrística', 'Davi morreu. Tertuliano comenta que Davi é um rei justo.', 'Tertuliano', 'commentary', '#6B21A8', NOW());

